                return saved
            }
            let now = Date()
            UserDefaults.standard.set(now, forKey: "installDate")
            return now
        }()
        return Store(initialState: AppFeature.State(installDate: installDate)) {
            AppFeature()
        }
    }()

    var body: some Scene {
        WindowGroup {
            AppView(store: store)
        }
        .modelContainer(for: Diary.self)
    }
}

