import Foundation
import ComposableArchitecture
import PhotosUI
import SwiftUI

@Reducer
struct GalleryFeature {
    @ObservableState
    struct State: Equatable {
        var isGalleryShowing: Bool = true
    }

    enum Action: BindableAction {
        case onDismiss
        case onPhotoSelected(UIImage)
        case closeGallery
        case reappear
        case binding(BindingAction<State>)
    }

    @Dependency(\.dismiss) var dismiss

    var body: some ReducerOf<Self> {
        BindingReducer()
        Reduce<State, Action> { state, action in
            switch action {
            case .closeGallery:
                state.isGalleryShowing = false
                return .none
            case .onDismiss:
                return .run { _ in
                    await self.dismiss()
                }
            case .reappear:
                // SnapshotEdit 화면에서 돌아온 경우
                if !state.isGalleryShowing {
                    state.isGalleryShowing = true
                }
                return .none
            default:
                return .none
            }
        }
    }
}

