import SwiftUI
import ComposableArchitecture
import Dependencies
import Foundation

@main
struct ggaebizApp: App {
    enum CurrentScreen {
        case splash
        case onboarding
        case main
    }

    @UIApplicationDelegateAdaptor(AppDelegate.self) var appDelegate
    @Dependency(\.notificationManager) private var notificationManager
    @Dependency(\.userDefaults) private var userDefaults

    @State private var currentScreen: CurrentScreen = .splash

    init() {
        notificationManager.setup()
    }

    var body: some Scene {
        let splashStore = Store(initialState: SplashFeature.State(), reducer: { SplashFeature() })
        let mainStore = Store(initialState: MainFeature.State(), reducer: { MainFeature() })
        let onboardingStore = Store(initialState: OnboardingFeature.State(), reducer: {
            OnboardingFeature()
        })

        WindowGroup {
            WithPerceptionTracking {
                switch currentScreen {
                case .splash:
                    SplashView(store: splashStore)
                        .onChange(of: splashStore.isFinished) { _ in
                            currentScreen = userDefaults.needsOnboarding() ? .onboarding : .main
                        }
                case .onboarding:
                    OnboardingView(store: onboardingStore)
                        .onChange(of: onboardingStore.isFinished) { _ in
                            currentScreen = .main
                        }
                case .main:
                    MainView(store: mainStore)
                }
            }
        }
    }
}

class AppDelegate: NSObject, UIApplicationDelegate {
    func application(
        _ application: UIApplication,
        configurationForConnecting connectingSceneSession: UISceneSession,
        options: UIScene.ConnectionOptions
    ) -> UISceneConfiguration {
        let sceneConfig: UISceneConfiguration = UISceneConfiguration(
            name: nil,
            sessionRole: connectingSceneSession.role
        )
        sceneConfig.delegateClass = SceneDelegate.self
        return sceneConfig
    }
}

class SceneDelegate: NSObject, UIWindowSceneDelegate {
    @Dependency(\.timerSettingManager) private var timerSettingManager

    func sceneDidDisconnect(_ scene: UIScene) {
        timerSettingManager.removeTimer()
    }
}

