//
//  SplashFeature.swift
//  ggaebiz
//
//  Created by suyeon on 2/9/25.
//

import ComposableArchitecture
import Foundation

@Reducer
struct SplashFeature {
    @ObservableState
    struct State: Equatable {
        var isAnimating: Bool = false
        var isFinished: Bool = false
    }

    enum Action {
        case onLoad
        case triggerAnimation
        case animationStopped
    }

    @Dependency(\.continuousClock) private var clock
    private let animationDuration = 0.8
    private let waitingDuration = 1.0

    var body: some ReducerOf<Self> {
        Reduce<State, Action> { state, action in
            switch action {
            case .onLoad:
                return .run { send in
                    try await clock.sleep(for: .seconds(waitingDuration))
                    await send(.triggerAnimation, animation: .linear(duration: animationDuration))
                }

            case .triggerAnimation:
                state.isAnimating = true

                return .run { send in
                    try await clock.sleep(for: .seconds(animationDuration + 0.8))
                    await send(.animationStopped)
                }

            case .animationStopped:
                state.isFinished = true
                return .none
            }
        }
    }
}

