//  TimerSettingFeature.swift
//  ggaebiz
//
//  Created by mirim.kim on 1/26/25.
//

import ComposableArchitecture
import Foundation

@Reducer
struct TimerSettingFeature {
    enum Mode: String, Equatable {
        case rest = "휴식"
        case focus = "집중"
    }

    @ObservableState
    struct State: Equatable {
        var hour: Int = 0
        var minute: Int = 15
        var hourRange: [Int] = Array(0...5)
        var level: Level = .one
        var focusCategory: FocusCategory = .general
        var buttonEnabled: Bool = true
        var showTooltip: Bool = true
        var selectedMode: Mode = .rest
        var isLevelSettingBottomSheetPresented: Bool = false
    }

    enum Action: BindableAction {
        case modeChanged(Mode)
        case chooseLevelButtonTapped
        case restModeLevelChanged(Level)
        case focusCategoryChanged(FocusCategory)
        case pickerScrollStarted
        case hourSelected(Int)
        case minuteSelected(Int)
        case backButtonTapped
        case startTimerButtonTapped(AvatarType)
        case setupTimer(TimerEntity)
        case binding(BindingAction<State>)
    }

    @Dependency(\.dismiss) var dismiss
    var body: some ReducerOf<Self> {
        BindingReducer()
        Reduce<State, Action> { state, action in
            switch action {
            case let .modeChanged(mode):
                state.selectedMode = mode
                return resetTimerPicker(state: &state)
            case .chooseLevelButtonTapped:
                state.isLevelSettingBottomSheetPresented = true
                return .none
            case let .restModeLevelChanged(level):
                state.level = level
                state.isLevelSettingBottomSheetPresented = false
                return .none
            case let .focusCategoryChanged(category):
                state.focusCategory = category
                return resetTimerPicker(state: &state)
            case .pickerScrollStarted:
                state.buttonEnabled = false
                return .none
            case let .hourSelected(hour):
                state.hour = hour
                state.buttonEnabled = !(state.minute == 0 && state.hour == 0)
                return .none
            case let .minuteSelected(minute):
                state.minute = minute
                state.buttonEnabled = !(state.minute == 0 && state.hour == 0)
                return .none
            case .backButtonTapped:
                return .run { _ in
                    await self.dismiss()
                }
            case let .startTimerButtonTapped(avatarType):
                return .run { [hour = state.hour, minute = state.minute, level = state.level, selectedMode = state.selectedMode, focusCategory = state.focusCategory] send in

                    let timeInterval = TimeInterval(hour * 3600 + minute * 60)
                    let mode: TimerMode = {
                        switch selectedMode {
                        case .rest:
                            return .rest(.init(level: level, snoozeLeftCount: 3))
                        case .focus:
                            return .focus(focusCategory)
                        }
                    }()
                    let timerEndName = avatarType.timerEndVoiceName(for: mode)

                    let newTimer = TimerEntity(
                        avatar: avatarType,
                        startTime: .now,
                        duration: timeInterval,
                        timerEndName: timerEndName,
                        mode: mode,
                        now: .now
                    )

                    await send(.setupTimer(newTimer))
                    await self.dismiss()
                }
            default:
                return .none
            }
        }
    }
}

private extension TimerSettingFeature {
    func resetTimerPicker(
        state: inout State
    ) -> Effect<Action> {
        state.hourRange = Array(0...5)

        switch state.selectedMode {
        case .rest:
            state.hour = 0
            state.minute = 15
        case .focus:
            switch state.focusCategory {
            case .general:
                state.hour = 0
                state.minute = 30
            case .study:
                state.hour = 2
                state.minute = 0
            case .workout:
                state.hour = 1
                state.minute = 0
                state.hourRange = Array(0...2)
            }
        }
        return .none
    }
}

